broken_code:
use std::time::Duration;

async fn wait_and_greet(delay: Duration) -> String {
    // Mistake: calling std::thread::sleep instead of the async equivalent
    std::thread::sleep(delay);
    String::from("hello")
}

#[tokio::main]
async fn main() {
    let result = wait_and_greet(Duration::from_millis(100)).await;
    println!("{}", result);
}

error_message:
// This compiles, but blocks the tokio executor thread during the sleep,
// which prevents other tasks from running. The correct error pattern shows
// when someone writes:
//   let fut = Duration::from_millis(100);
//   fut.await;  // error[E0277]: Duration doesn't implement Future
//
error[E0277]: `Duration` is not a future
 --> src/main.rs:5:5
  |
5 |     Duration::from_millis(100).await;
  |     ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^ `Duration` is not a future
  |
  = help: the trait `Future` is not implemented for `Duration`
  = note: Duration does not describe an asynchronous computation

fixed_code:
use std::time::Duration;
use tokio::time;

async fn wait_and_greet(delay: Duration) -> String {
    // Correct: tokio::time::sleep is an async fn that returns a Future
    time::sleep(delay).await;
    String::from("hello")
}

#[tokio::main]
async fn main() {
    let result = wait_and_greet(Duration::from_millis(10)).await;
    println!("{}", result);
}

