use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

struct Countdown {
    remaining: u32,
}

impl Future for Countdown {
    type Output = u32;

    fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<u32> {
        if self.remaining == 0 {
            return Poll::Ready(0);
        }
        self.remaining -= 1;
        // BUG: returning Pending without registering a waker means
        // the executor will never poll this future again
        Poll::Pending
    }
}

#[tokio::main]
async fn main() {
    let result = Countdown { remaining: 3 }.await;
    println!("countdown finished: {}", result);
}

fixed_code:
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

struct Countdown {
    remaining: u32,
}

impl Future for Countdown {
    type Output = u32;

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<u32> {
        if self.remaining == 0 {
            return Poll::Ready(0);
        }
        self.remaining -= 1;
        // Tell the executor to poll us again immediately by waking now.
        // In a real timer you'd register the waker with a timer wheel instead.
        cx.waker().wake_by_ref();
        Poll::Pending
    }
}

#[tokio::main]
async fn main() {
    let result = Countdown { remaining: 3 }.await;
    println!("countdown finished: {}", result);
}

broken_code:
use std::rc::Rc;
use tokio;

async fn process(data: Rc<Vec<i32>>) -> i32 {
    // await point: suspends the future, captures `data` across the suspension
    tokio::task::yield_now().await;
    data.iter().sum()
}

#[tokio::main]
async fn main() {
    let data = Rc::new(vec![1, 2, 3]);
    // tokio::spawn requires the future to be Send
    tokio::spawn(process(data)).await.unwrap();
}

fixed_code:
use std::sync::Arc;
use tokio;

async fn process(data: Arc<Vec<i32>>) -> i32 {
    tokio::task::yield_now().await;
    data.iter().sum()
}

#[tokio::main]
async fn main() {
    let data = Arc::new(vec![1, 2, 3]);
    let result = tokio::spawn(process(data)).await.unwrap();
    println!("sum = {}", result);

    // Alternatively, use tokio::task::spawn_local for non-Send futures
    // (requires a LocalSet)
}

