fixed_code:
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

struct Mapped<F, T> {
    inner: F,
    func: Option<Box<dyn FnOnce(F::Output) -> T>>,
}

impl<F: Future, T> Future for Mapped<F, T> {
    type Output = T;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<T> {
        // SAFETY: we never move `inner` or `func` out of `self`
        let this = unsafe { self.get_unchecked_mut() };
        // Project to inner, pinning it in place
        let inner = unsafe { Pin::new_unchecked(&mut this.inner) };
        match inner.poll(cx) {
            Poll::Ready(val) => {
                let f = this.func.take().expect("polled after completion");
                Poll::Ready(f(val))
            }
            Poll::Pending => Poll::Pending,
        }
    }
}

fn main() {}

