// On Rust before 1.75 — async fn in trait is not stable
trait DataFetcher {
    async fn fetch(&self, id: u32) -> String;
}

struct HttpFetcher;

impl DataFetcher for HttpFetcher {
    async fn fetch(&self, id: u32) -> String {
        format!("data-{}", id)
    }
}

async fn load(fetcher: &impl DataFetcher) -> String {
    fetcher.fetch(1).await
}

fn main() {}

fixed_code:
// Option A: async-trait crate (works on all Rust editions, boxes the future)
use async_trait::async_trait;

#[async_trait]
trait DataFetcher {
    async fn fetch(&self, id: u32) -> String;
}

struct HttpFetcher;

#[async_trait]
impl DataFetcher for HttpFetcher {
    async fn fetch(&self, id: u32) -> String {
        format!("data-{}", id)
    }
}

// Option B: native async fn in trait (stable since Rust 1.75, limited to non-dyn use)
// trait DataFetcher {
//     async fn fetch(&self, id: u32) -> String;
// }

#[tokio::main]
async fn main() {
    let fetcher = HttpFetcher;
    println!("{}", fetcher.fetch(1).await);
}
